#include<stdio.h>
#include<math.h>
int main(){
	int n;
	scanf("%d",&n);
	int t=0;
	for(int i=1;i<n;i++){
		int o=1;
		long long int ans=i;
		while(o!=n-1){
			if((ans-1)%n==0){
				break;
			}
			else{
				o++;
				ans=(ans*i)%n;
			}
		}
		if(o==n-1){
			if((ans)%n==1){
			t++;	
			}
		}
	}
	printf("%d\n",t);
}

